    "paper_claims": {c.get("method", ""): c.get("expected_result", "") for c in paper_claim_map.get("claims", [])},
    "rubric": {
        "overall_score": best_score,
        "meets_target": best_rubric.get("meets_target", False) if best_rubric else False,
        "areas": best_areas,
    },
    "improvements": [
        {
            "title": top_imp.get("title", "") if improvements else "",
            "outcome": "promoted" if (best_rubric and best_rubric.get("overall_score", 0) > rubric_result.get("overall_score", 0)) else "failed",
