        }
    ] if improvements else [],
    "scope": {
        "requested": "baseline reproduction of core claims",
        "ran": [str(best_run.get("metrics", {}).keys()) if best_run else "none"],
        "gaps": [],
    },
    "primitive_trace": {
        "calls": 10,
        "by_primitive": {
            "understand_section": 3,
            "extract_hyperparameters": 1,
            "detect_environment": 1,
            "build_environment": 1,
            "plan_reproduction": 1,
            "implement_baseline": 2,
            "run_experiment": 2,
            "verify_against_rubric": 2,
            "propose_improvements": 1,
        }
    },
    "cost": {"llm_usd": 0.0},
    "iterations": 3,
}

report_json = json.dumps(final_report, default=str)
print("Report length:", len(report_json))
print("Verdict:", final_report["verdict"])
print("Score:", final_report["rubric"]["overall_score"])

